module synchronizer
(
    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input [3:0] data_in,
    input data_en,
    output reg [3:0] dataout
);
// DO NOT MODIFY or DELETE THIS always @(*) BLOCK!
// THIS IS THE PROVIDED SKELETON CODE.
// START YOUR CODE AFTER THIS BLOCK.
    always @(*) begin
        if (!arstn)
            dataout = 4'd0;
        else if (en_clap_two)
            dataout = data_reg;
        else
            dataout = dataout;
    end
// END OF SKELETON CODE
// DELETE THESE COMMENTS AFTER FILLING IN YOUR logic_description
// Declare your reg parameters (if any) below
    reg [3:0] data_reg;
    reg [3:0] en_data_reg;
    reg [3:0] en_clap_one;
    reg [3:0] en_clap_two;
// Declare your wire parameters (if any) below
// Implement your logic description here
    always @(posedge clk_a or negedge arstn) begin
        if (!arstn)
            data_reg <= 4'd0;
        else
            data_reg <= data_in;
    end
    always @(posedge clk_a or negedge arstn) begin
        if (!arstn)
            en_data_reg <= 4'd0;
        else
            en_data_reg <= data_en;
    end
    always @(posedge clk_b or negedge brstn) begin
        if (!brstn)
            en_clap_one <= 4'd0;
        else
            en_clap_one <= en_data_reg;
    end
    always @(posedge clk_b or negedge brstn) begin
        if (!brstn)
            en_clap_two <= 4'd0;
        else
            en_clap_two <= en_clap_one;
    end
endmodule
